// src/pages/Calendar.js

import React, { useEffect, useState } from 'react';
import FullCalendar from '@fullcalendar/react'; // import FullCalendar component
import dayGridPlugin from '@fullcalendar/daygrid'; // import the dayGrid plugin
import interactionPlugin from '@fullcalendar/interaction'; // import interaction plugin (for events interaction)
import axios from 'axios'; // for making API requests

const Calendar = () => {
  // State to store fetched events
  const [events, setEvents] = useState([]);

  // Function to handle event clicks
  const handleEventClick = (info) => {
    info.jsEvent.preventDefault(); // prevent default action (opening the link)
    if (info.event.url) {
      window.open(info.event.url); // open event link in a new tab if available
    }
  };

  // Fetch events from the backend API
  useEffect(() => {
    axios.get('http://127.0.0.1:3001/events') // Adjust if needed
      .then((response) => {
        console.log('Fetched events:', response.data); // Log the events
        setEvents(response.data); // Set events to state
      })
      .catch((error) => {
        console.error('Error fetching events:', error);
      });
  }, []); // Empty array means it will run once after the first render

  return (
    <div>
      <h1>Calendar</h1>
      <FullCalendar
        plugins={[dayGridPlugin, interactionPlugin]} // use the necessary plugins
        initialView="dayGridMonth" // set initial view
        events={events} // pass events to FullCalendar
        eventClick={handleEventClick} // handle event clicks
      />
    </div>
  );
};

export default Calendar;
